VALUES
  ('social-worker-moex-00541', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '占領華爾街集會活動的目標，是反抗大公司的貪婪不公和社會的不平等。這樣凸顯貧富差距的社 會行動，屬於下列何種理論思想？', '["衝突論", "交換論", "功能論", "符號互動論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00542', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關貧富差距日益擴大的導因和現象，下列敘述何者錯誤？', '["下滲經濟學（trickledowneconomics）政策支持企業減稅，可鼓勵有錢人將省下的錢花在服務及 財物的消費上，使所有人都受益", "致富與成功是因為他們努力工作，貧窮與失敗完全是因為他們過於懶惰", "高學費、房價、健康照顧成本等財富不平均分配現象，正侵蝕崩解著中產階級", "自由市場的資本主義造成這種差距"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00543', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '低社經地位對於兒童發展是多面向的影響，有關低社經地位造成的影響，下列敘述何者錯誤？', '["社經地位是精神疾病唯一影響因素", "兒童可能由於低社經地位造成的資源匱乏而出現適應不良議題", "低社經地位可能導致無法取得足夠食物，對大腦發展和功能有長期和慢性影響", "兒童可能因為社經地位而在學校受到歧視與霸凌"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00544', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '一般認為退休老年人多半擁有財富，較不易遭遇貧窮議題。事實上，老年貧困人口比例並不低。 關於老年貧窮的敘述，下列何者錯誤？', '["婦女和少數族裔在高齡階段比白人男子更容易陷入貧困", "生活在貧困中可能給老年人帶來其他的問題，如壓力、長期疾病等", "老年人陷入貧困是一個短暫的問題", "喪偶、失能、慢性疾病、醫療費用增加等，可能導致老年貧困"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00545', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '若父母發現孩子課業和人際關係不佳、自信心嚴重不足而需要求助，這是在艾力克森（Erikson） 的發展理論中，那一階段的發展危機？', '["幼兒期", "兒童早期", "兒童中期", "青少年期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00546', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關艾力克森（Erikson）心理社會發展理論，下列敘述何者錯誤？', '["幼兒時期的主要發展危機是當父母時常限制或處罰孩子，他們會對自己的能力感到懷疑", "父母能幫助兒童主動自發學習代表兒童早期的成功發展", "青年期的主要發展危機是若家庭無法提供協助個人了解自我，會使其在生活中扮演的角色產生 疑惑", "家庭能協助老年人接納自己的人生是老年期的成功發展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
